import {
  createContext,
  useCallback,
  useContext,
  useEffect,
  useMemo,
  useRef,
  useState,
  type ReactNode,
} from 'react';
import { createPortal } from 'react-dom';
import { cn, vc } from '../../utils/cn';
import styles from './Toast.module.css';

export type ToastVariant = 'success' | 'error' | 'warning' | 'info';

export interface ToastOptions {
  title: string;
  description?: string;
  variant?: ToastVariant;
  /** Auto-dismiss after ms. 0 = never. Default 5000. */
  duration?: number;
  action?: { label: string; onClick: () => void };
}

interface ToastEntry extends ToastOptions {
  id: string;
}

interface ToastContextValue {
  toast: (opts: ToastOptions) => string;
  dismiss: (id: string) => void;
}
const ToastContext = createContext<ToastContextValue | null>(null);

export function useToast(): ToastContextValue {
  const ctx = useContext(ToastContext);
  if (!ctx)
    throw new Error(
      'useToast must be used inside <ToastProvider>. Wrap your app in <ToastProvider>.',
    );
  return ctx;
}

export interface ToastProviderProps {
  children: ReactNode;
  position?: 'top-right' | 'top-left' | 'bottom-right' | 'bottom-left';
}

const iconFor: Record<ToastVariant, string> = {
  success: '✓',
  error: '✕',
  warning: '!',
  info: 'i',
};

export function ToastProvider({
  children,
  position = 'top-right',
}: ToastProviderProps) {
  const [items, setItems] = useState<ToastEntry[]>([]);
  const timers = useRef<Map<string, ReturnType<typeof setTimeout>>>(new Map());

  const dismiss = useCallback((id: string) => {
    setItems((prev) => prev.filter((t) => t.id !== id));
    const t = timers.current.get(id);
    if (t) {
      clearTimeout(t);
      timers.current.delete(id);
    }
  }, []);

  const startTimer = useCallback(
    (id: string, duration: number) => {
      if (duration === 0) return;
      const timer = setTimeout(() => dismiss(id), duration);
      timers.current.set(id, timer);
    },
    [dismiss],
  );

  const clearTimer = (id: string) => {
    const t = timers.current.get(id);
    if (t) {
      clearTimeout(t);
      timers.current.delete(id);
    }
  };

  const toast = useCallback(
    (opts: ToastOptions) => {
      const id = `toast-${Date.now()}-${Math.random().toString(36).slice(2, 7)}`;
      const entry: ToastEntry = {
        id,
        variant: 'info',
        duration: 5000,
        ...opts,
      };
      setItems((prev) => [...prev, entry]);
      startTimer(id, entry.duration ?? 5000);
      return id;
    },
    [startTimer],
  );

  useEffect(
    () => () => {
      timers.current.forEach(clearTimeout);
      timers.current.clear();
    },
    [],
  );

  const value = useMemo(() => ({ toast, dismiss }), [toast, dismiss]);

  return (
    <ToastContext.Provider value={value}>
      {children}
      {typeof document !== 'undefined' &&
        createPortal(
          <div
            className={cn(styles.container, vc(styles, 'position', position))}
            aria-live="polite"
            role="status"
          >
            {items.map((t) => {
              const variant = t.variant ?? 'info';
              return (
                <div
                  key={t.id}
                  className={cn(styles.toast, vc(styles, 'variant', variant))}
                  role={variant === 'error' ? 'alert' : 'status'}
                  onMouseEnter={() => clearTimer(t.id)}
                  onMouseLeave={() => startTimer(t.id, t.duration ?? 5000)}
                  data-testid="tatva-toast"
                >
                  <span className={styles.icon} aria-hidden="true">
                    {iconFor[variant]}
                  </span>
                  <div className={styles.body}>
                    <div className={styles.title}>{t.title}</div>
                    {t.description && (
                      <div className={styles.description}>{t.description}</div>
                    )}
                  </div>
                  {t.action && (
                    <button
                      type="button"
                      className={styles.action}
                      onClick={() => {
                        t.action?.onClick();
                        dismiss(t.id);
                      }}
                    >
                      {t.action.label}
                    </button>
                  )}
                  <button
                    type="button"
                    className={styles.close}
                    aria-label="Close notification"
                    onClick={() => dismiss(t.id)}
                  >
                    ×
                  </button>
                </div>
              );
            })}
          </div>,
          document.body,
        )}
    </ToastContext.Provider>
  );
}

.container {
  position: fixed;
  z-index: var(--tatva-z-toast);
  display: flex;
  flex-direction: column;
  gap: var(--tatva-space-2);
  padding: var(--tatva-space-4);
  pointer-events: none;
  max-width: 400px;
}

.positionTopRight {
  top: 0;
  right: 0;
}
.positionTopLeft {
  top: 0;
  left: 0;
}
.positionBottomRight {
  bottom: 0;
  right: 0;
}
.positionBottomLeft {
  bottom: 0;
  left: 0;
}

.toast {
  display: flex;
  align-items: flex-start;
  gap: var(--tatva-space-3);
  background-color: var(--tatva-color-bg);
  color: var(--tatva-color-fg);
  border: 1px solid var(--tatva-color-border);
  border-left: 4px solid var(--tatva-color-info);
  border-radius: var(--tatva-radius-md);
  padding: var(--tatva-space-3) var(--tatva-space-4);
  box-shadow: var(--tatva-shadow-lg);
  font-family: var(--tatva-font-family);
  pointer-events: auto;
  animation: tatva-toast-in 200ms ease;
  min-width: 280px;
}

.variantSuccess {
  border-left-color: var(--tatva-color-success);
}
.variantError {
  border-left-color: var(--tatva-color-error);
}
.variantWarning {
  border-left-color: var(--tatva-color-warning);
}
.variantInfo {
  border-left-color: var(--tatva-color-info);
}

.icon {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 20px;
  height: 20px;
  border-radius: 50%;
  color: #ffffff;
  font-weight: var(--tatva-font-weight-bold);
  font-size: 12px;
  flex: 0 0 auto;
  margin-top: 2px;
}

.variantSuccess .icon {
  background-color: var(--tatva-color-success);
}
.variantError .icon {
  background-color: var(--tatva-color-error);
}
.variantWarning .icon {
  background-color: var(--tatva-color-warning);
}
.variantInfo .icon {
  background-color: var(--tatva-color-info);
}

.body {
  flex: 1;
  min-width: 0;
}

.title {
  font-weight: var(--tatva-font-weight-semibold);
  font-size: var(--tatva-font-size-sm);
}

.description {
  color: var(--tatva-color-fg-muted);
  font-size: var(--tatva-font-size-sm);
  margin-top: var(--tatva-space-1);
}

.action {
  background: transparent;
  border: none;
  color: var(--tatva-color-primary-700);
  font-weight: var(--tatva-font-weight-semibold);
  font-family: inherit;
  font-size: var(--tatva-font-size-sm);
  cursor: pointer;
  padding: var(--tatva-space-1) var(--tatva-space-2);
  border-radius: var(--tatva-radius-sm);
}
.action:hover {
  background-color: var(--tatva-color-primary-50);
}

.close {
  background: transparent;
  border: none;
  color: var(--tatva-color-fg-muted);
  cursor: pointer;
  font-size: 18px;
  line-height: 1;
  padding: var(--tatva-space-1);
  border-radius: var(--tatva-radius-sm);
}
.close:hover {
  background-color: var(--tatva-color-neutral-100);
  color: var(--tatva-color-fg);
}

@keyframes tatva-toast-in {
  from {
    transform: translateX(20px);
    opacity: 0;
  }
  to {
    transform: translateX(0);
    opacity: 1;
  }
}
